define("mod_glaaster/tool_configure_controller",["jquery","core/ajax","core/notification","core/str","mod_glaaster/events","mod_glaaster/tool_types_and_proxies","core/config"],function($,ajax,notification,str,ltiEvents,toolTypesAndProxies,config){var SELECTORS={EXTERNAL_REGISTRATION_CONTAINER:"#external-registration-container",EXTERNAL_REGISTRATION_PAGE_CONTAINER:"#external-registration-page-container",EXTERNAL_REGISTRATION_TEMPLATE_CONTAINER:"#external-registration-template-container",TOOL_STATUS_CONTAINER:"#tool-status-container",TOOL_CREATE_BUTTON:"#tool-create-button",REGISTRATION_CHOICE_CONTAINER:"#registration-choice-container"};var getExternalRegistrationContainer=function(){return $(SELECTORS.EXTERNAL_REGISTRATION_CONTAINER)};var getRegistrationChoiceContainer=function(){return $(SELECTORS.REGISTRATION_CHOICE_CONTAINER)};var getToolStatusContainer=function(){return $(SELECTORS.TOOL_STATUS_CONTAINER)};var closeLTIAdvRegistration=function(e){if(e.data&&"org.imsglobal.lti.close"===e.data.subject){$(SELECTORS.EXTERNAL_REGISTRATION_TEMPLATE_CONTAINER).empty();hideExternalRegistration();showRegistrationChoices();reloadToolStatus()}};var initiateRegistration=function(url){$(SELECTORS.EXTERNAL_REGISTRATION_PAGE_CONTAINER).removeClass("hidden");var container=$(SELECTORS.EXTERNAL_REGISTRATION_TEMPLATE_CONTAINER);container.append($('<iframe src="'+config.wwwroot+"/mod/glaaster/startltiadvregistration.php?url="+encodeURIComponent(url)+"&sesskey="+config.sesskey+'"></iframe>'));showExternalRegistration();window.addEventListener("message",closeLTIAdvRegistration,false)};var hideExternalRegistration=function(){getExternalRegistrationContainer().addClass("hidden")};var showExternalRegistration=function(){getRegistrationChoiceContainer().addClass("hidden");getExternalRegistrationContainer().removeClass("hidden");screenReaderAnnounce(getExternalRegistrationContainer())};var showRegistrationChoices=function(){hideExternalRegistration();getRegistrationChoiceContainer().removeClass("hidden");screenReaderAnnounce(getRegistrationChoiceContainer())};var screenReaderAnnounce=function(element){var children=element.children().detach();children.appendTo(element)};var showRegistrationFeedback=function(data){var type=data.error?"error":"success";notification.addNotification({message:data.message,type:type})};var renderToolStatus=function(tool){var container=getToolStatusContainer();container.empty();if(!tool){return}var element=$('<div class="tool-status-row d-flex align-items-center gap-1"></div>');element.attr("data-type-id",tool.id);element.attr("data-platformid",tool.platformid||"");element.attr("data-clientid",tool.clientid||"");element.attr("data-deploymentid",tool.deploymentid||"");element.attr("data-statusurl",tool.statusurl||"");var badge=$('<span class="glaaster-status-pill status-pending tool-connection-status"><span class="status-dot"></span><span class="status-text"></span></span>');element.append(badge);if(tool.urls&&tool.urls.edit){var editBtn=$('<a class="glaaster-tool-action glaaster-tool-action-edit" title="Edit"></a>');editBtn.attr("href",tool.urls.edit);editBtn.append($('<span class="fa fa-pencil" aria-hidden="true"></span>'));element.append(editBtn)}var deleteBtn=$('<button type="button" class="glaaster-tool-action glaaster-tool-action-delete" title="Delete"></button>');deleteBtn.append($('<span class="fa fa-trash" aria-hidden="true"></span>'));deleteBtn.on("click",function(){deleteTool(tool.id,element)});element.append(deleteBtn);container.append(element);checkConnectionStatus(element,tool)};var checkConnectionStatus=function(element,tool){if(!tool.statusurl||!tool.clientid||!tool.platformid){element.find(".tool-connection-status").addClass("d-none");return}str.get_strings([{key:"connect_status_pending",component:"mod_glaaster"},{key:"connect_status_validated",component:"mod_glaaster"},{key:"connect_status_error",component:"mod_glaaster"},{key:"connect_status_api_pending",component:"mod_glaaster"}]).then(function(strings){var pill=element.find(".tool-connection-status");pill.find(".status-text").text(strings[0]);ajax.call([{methodname:"mod_glaaster_check_tool_status",args:{statusurl:tool.statusurl,iss:tool.platformid,client_id:tool.clientid}}])[0].then(function(result){pill.removeClass("status-pending status-validated status-error");if(result.active===true){pill.addClass("status-validated").find(".status-text").text(strings[1])}else if(result.status==="PENDING"||result.status===""){pill.addClass("status-pending").find(".status-text").text(strings[3])}else{pill.addClass("status-error").find(".status-text").text(strings[2])}return result}).catch(function(){pill.removeClass("status-pending status-validated").addClass("status-error").find(".status-text").text(strings[2])});return strings}).catch(function(){element.find(".tool-connection-status").addClass("d-none")})};var deleteTool=function(typeId,element){str.get_strings([{key:"delete",component:"mod_glaaster"},{key:"delete_confirmation",component:"mod_glaaster"},{key:"delete",component:"mod_glaaster"},{key:"cancel",component:"core"}]).done(function(strs){notification.confirm(strs[0],strs[1],strs[2],strs[3],function(){ajax.call([{methodname:"mod_glaaster_delete_tool_type",args:{id:typeId}}])[0].then(function(){element.remove();$(SELECTORS.TOOL_CREATE_BUTTON).prop("disabled",false).removeAttr("disabled");return}).catch(notification.exception)})}).fail(notification.exception)};var reloadToolStatus=function(){M.util.js_pending("reloadToolStatus");toolTypesAndProxies.query({orphanedonly:true,limit:1,offset:0}).then(function(data){var tool=(data.types&&data.types.length>0)?data.types[0]:null;if(tool){$(SELECTORS.TOOL_CREATE_BUTTON).prop("disabled",true).attr("disabled","disabled")}else{$(SELECTORS.TOOL_CREATE_BUTTON).prop("disabled",false).removeAttr("disabled")}renderToolStatus(tool);return data}).catch(function(error){notification.exception(error)}).always(function(){M.util.js_complete("reloadToolStatus")})};var registerEventListeners=function(){$(document).on(ltiEvents.NEW_TOOL_TYPE,function(){reloadToolStatus()});$(document).on(ltiEvents.STOP_EXTERNAL_REGISTRATION,function(){showRegistrationChoices()});$(document).on(ltiEvents.REGISTRATION_FEEDBACK,function(event,data){showRegistrationFeedback(data)});$(SELECTORS.TOOL_CREATE_BUTTON).click(function(e){e.preventDefault();var url=$(this).data("registerurl");var token=$(this).data("apitoken");if(token){var separator=url.indexOf("?")!==-1?"&":"?";url=url+separator+"token="+encodeURIComponent(token)}initiateRegistration(url)})};return{init:function(){registerEventListeners();reloadToolStatus()}}});
